const fs=require("fs").promises,path=require("path");class AlertsDatabase{constructor(){this.dbPath=path.join(__dirname,"..","data","alerts.json"),this.alerts=new Map,this.initialized=!1}async initialize(){try{const dataDir=path.dirname(this.dbPath);try{await fs.access(dataDir)}catch{await fs.mkdir(dataDir,{recursive:!0})}try{const data=await fs.readFile(this.dbPath,"utf8"),alertsData=JSON.parse(data);for(const[userId,userAlerts]of Object.entries(alertsData))this.alerts.set(userId,userAlerts);console.log(`📝 Loaded ${Object.keys(alertsData).length} users' alerts from database`)}catch(error){"ENOENT"===error.code?console.log("📝 No existing alerts database found, starting fresh"):console.error("❌ Error loading alerts database:",error.message)}return this.initialized=!0,!0}catch(error){return console.error("❌ Failed to initialize alerts database:",error.message),!1}}async saveToFile(){if(!this.initialized)return!1;try{const alertsData={};for(const[userId,userAlerts]of this.alerts.entries())userAlerts.length>0&&(alertsData[userId]=userAlerts);return await fs.writeFile(this.dbPath,JSON.stringify(alertsData,null,2)),!0}catch(error){return console.error("❌ Error saving alerts database:",error.message),!1}}async addAlert(alert){if(!this.initialized)return!1;try{const userId=alert.userId;this.alerts.has(userId)||this.alerts.set(userId,[]);return this.alerts.get(userId).push(alert),await this.saveToFile(),console.log(`✅ Alert ${alert.id} added to database for user ${alert.username}`),!0}catch(error){return console.error("❌ Error adding alert to database:",error.message),!1}}async removeAlert(userId,alertId){if(!this.initialized)return!1;try{if(!this.alerts.has(userId))return!1;const userAlerts=this.alerts.get(userId),initialLength=userAlerts.length,filteredAlerts=userAlerts.filter((alert=>alert.id!==alertId));return filteredAlerts.length!==initialLength&&(this.alerts.set(userId,filteredAlerts),await this.saveToFile(),console.log(`✅ Alert ${alertId} removed from database`),!0)}catch(error){return console.error("❌ Error removing alert from database:",error.message),!1}}async removeAllUserAlerts(userId){if(!this.initialized)return!1;try{if(!this.alerts.has(userId))return 0;const removedCount=this.alerts.get(userId).length;return this.alerts.delete(userId),await this.saveToFile(),console.log(`✅ Removed ${removedCount} alerts for user ${userId}`),removedCount}catch(error){return console.error("❌ Error removing user alerts from database:",error.message),0}}async removeAllActiveUserAlerts(userId){if(!this.initialized)return 0;try{if(!this.alerts.has(userId))return 0;const userAlerts=this.alerts.get(userId),remaining=userAlerts.filter((alert=>!1===alert.active)),removedCount=userAlerts.length-remaining.length;return this.alerts.set(userId,remaining),await this.saveToFile(),console.log(`✅ Removed ${removedCount} active alerts for user ${userId}`),removedCount}catch(error){return console.error("❌ Error removing active user alerts from database:",error.message),0}}getUserAlerts(userId){return this.initialized&&this.alerts.get(userId)||[]}getAllAlerts(){if(!this.initialized)return[];const allAlerts=[];for(const userAlerts of this.alerts.values())allAlerts.push(...userAlerts);return allAlerts}getActiveAlerts(){return this.getAllAlerts().filter((alert=>!1!==alert.active))}async updateAlert(userId,alertId,updates){if(!this.initialized)return!1;try{if(!this.alerts.has(userId))return!1;const userAlerts=this.alerts.get(userId),alertIndex=userAlerts.findIndex((alert=>alert.id===alertId));return-1!==alertIndex&&(Object.assign(userAlerts[alertIndex],updates),await this.saveToFile(),console.log(`✅ Alert ${alertId} updated in database`),!0)}catch(error){return console.error("❌ Error updating alert in database:",error.message),!1}}getStats(){if(!this.initialized)return{totalUsers:0,totalAlerts:0,activeAlerts:0};const totalUsers=this.alerts.size,allAlerts=this.getAllAlerts();return{totalUsers:totalUsers,totalAlerts:allAlerts.length,activeAlerts:allAlerts.filter((alert=>!1!==alert.active)).length}}}module.exports=AlertsDatabase;